import React from 'react';

import './sign-in.styles.scss';

class SignIn extends React.Component {
    constructor() {
        super()
        
        this.state = {
            email: '',
            password: ''
        }
    }

    handleSubmit = (event) => {
        event.preventDefault();

        this.setState({email: '', password:''});
    };

    handleChange = (event) => {
        const {name, value} = event.target;
        
        this.setState({[name]: value});
    };


    render() {
        return (
            <div className="sign-in">
                <h1> I already have an account </h1>
                <span> Sign in with your email or password </span>
                
                <form OnSubmit={this.handleSubmit} > 
                    <input name="email" type="email" value= {this.state.email} required OnChange={this.handleChange}/>
                    <label> email</label>
                    <input name="password" type="password" value= {this.state.password} required />
                    <label> password </label>
                    <input type="submit" value="Submit Form" OnChange={this.handleChange}/>
                </form>
            </div>
        )
    }
}

export default SignIn;
